import React, { useState, useEffect } from 'react';
import api from '../services/api';

function Clientes() {
    const [clientes, setClientes] = useState([]);
    const [form, setForm] = useState({ id: null, nome: '', telefone: '', email: '', endereco: '' });
    const [editando, setEditando] = useState(false);

    const carregar = async () => {
        const res = await api.get('/clientes');
        setClientes(res.data);
    };

    useEffect(() => { carregar(); }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editando) await api.put(`/clientes/${form.id}`, form);
            else await api.post('/clientes', form);
            setForm({ id: null, nome: '', telefone: '', email: '', endereco: '' });
            setEditando(false);
            carregar();
        } catch (err) { alert('Erro ao salvar'); }
    };

    const handleEdit = (c) => { setForm(c); setEditando(true); };
    const handleDelete = async (id) => {
        if (window.confirm('Excluir cliente? As OS associadas serão removidas.')) {
            await api.delete(`/clientes/${id}`);
            carregar();
        }
    };

    return (
        <div>
            <h2>Clientes</h2>
            <form onSubmit={handleSubmit} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '20px' }}>
                <input type="text" placeholder="Nome" value={form.nome} onChange={e => setForm({...form, nome: e.target.value})} required />
                <input type="text" placeholder="Telefone" value={form.telefone} onChange={e => setForm({...form, telefone: e.target.value})} required />
                <input type="email" placeholder="Email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
                <input type="text" placeholder="Endereço" value={form.endereco} onChange={e => setForm({...form, endereco: e.target.value})} />
                <button type="submit">{editando ? 'Atualizar' : 'Cadastrar'}</button>
                {editando && <button type="button" onClick={() => { setForm({ id: null, nome: '', telefone: '', email: '', endereco: '' }); setEditando(false); }}>Cancelar</button>}
            </form>
            <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead><tr><th>Nome</th><th>Telefone</th><th>Email</th><th>Endereço</th><th>Ações</th></tr></thead>
                <tbody>
                    {clientes.map(c => (
                        <tr key={c.id}>
                            <td>{c.nome}</td><td>{c.telefone}</td><td>{c.email}</td><td>{c.endereco}</td>
                            <td><button onClick={() => handleEdit(c)}>Editar</button> <button onClick={() => handleDelete(c.id)}>Excluir</button></td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default Clientes;
